import { unstable_cache } from 'next/cache';
import { revalidateTag } from 'next/cache';
import { getAllProducts, syncCatalog } from '@/lib/db';
import { CatalogContent } from './catalog-content';

// Dynamic rendering ensures fresh data is always fetched (from cache or
// re-fetched after invalidation) on every request to this admin page.
export const dynamic = 'force-dynamic';

// Cache the product list with the "products" tag so all catalog views share
// the same cache entry and a single revalidateTag call refreshes them all.
const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['admin-catalog-products'],
  { tags: ['products'] },
);

export default async function AdminCatalogPage() {
  const products = await getCachedProducts();

  /**
   * Inline Server Action — renders as a regular <form> POST so the browser
   * handles submission natively without client-side JS.
   *
   * 1. Fire syncCatalog() without awaiting it (background I/O).
   * 2. Immediately invalidate the "products" cache tag so the next read
   *    (after the sync settles) fetches fresh data.
   * 3. Return a status object the client component can display.
   */
  async function syncAction() {
    'use server';

    // Don't await — let the sync complete in the background.
    // eslint-disable-next-line @typescript-eslint/no-floating-promises
    syncCatalog();

    // Mark the cached catalog as stale — subsequent fetches with the
    // "products" tag will revalidate in the background (stale-while-revalidate).
    revalidateTag('products', { expire: 0 });

    return {
      success: true,
      message: 'Catalog sync started — product data will refresh shortly.',
    };
  }

  return (
    <CatalogContent
      products={products}
      syncAction={syncAction}
    />
  );
}


